function HistoryScreen() {
  const [history, setHistory] = useState([]);
  const [filteredHistory, setFilteredHistory] = useState([]);
  const [refreshing, setRefreshing] = useState(false);
  const [selectedFilter, setSelectedFilter] = useState('All');

  const categories = ['All', 'Organic', 'Inorganic'];

  useEffect(() => {
    loadHistory();
  }, []);

  useEffect(() => {
    applyFilter();
  }, [selectedFilter, history]);

  const loadHistory = async () => {
    try {
      const data = await getClassificationHistory();
      setHistory(data);
    } catch (error) {
      console.error('Error loading history:', error);
    }
  };

  const onRefresh = async () => {
    setRefreshing(true);
    await loadHistory();
    setRefreshing(false);
  };

  const applyFilter = () => {
    if (selectedFilter === 'All') {
      setFilteredHistory(history);
    } else {
      const filtered = filterByCategory(history, selectedFilter);
      setFilteredHistory(filtered);
    }
  };

  const renderItem = ({ item }) => (
    <View style={styles.itemContainer}>
      <Image source={{ uri: item.imageUri }} style={styles.thumbnail} />
      <View style={styles.itemInfo}>
        <Text style={styles.itemCategory}>
          {item.category}
        </Text>
        <Text style={styles.itemConfidence}>
          Confidence: {(item.confidence * 100).toFixed(1)}%
        </Text>
        <Text style={styles.itemDate}>
          {new Date(item.timestamp).toLocaleString()}
        </Text>
      </View>
      <View style={styles.confidenceIndicator}>
        <Ionicons
          name={item.confidence >= 0.7 ? 'checkmark-circle' : 'warning'}
          size={24}
          color={item.confidence >= 0.7 ? '#4CAF50' : '#FF9800'}
        />
      </View>
    </View>
  );

  const renderEmptyList = () => (
    <View style={styles.emptyContainer}>
      <Ionicons name="images-outline" size={64} color="#ccc" />
      <Text style={styles.emptyText}>No classification history yet</Text>
      <Text style={styles.emptySubText}>
        Start scanning waste items to see your history
      </Text>
    </View>
  );

  return (
    <View style={styles.container}>
      <View style={styles.filterContainer}>
        <FlatList
          horizontal
          showsHorizontalScrollIndicator={false}
          data={categories}
          keyExtractor={(item) => item}
          renderItem={({ item }) => (
            <TouchableOpacity
              style={[
                styles.filterButton,
                selectedFilter === item && styles.filterButtonActive,
              ]}
              onPress={() => setSelectedFilter(item)}
            >
              <Text
                style={[
                  styles.filterButtonText,
                  selectedFilter === item && styles.filterButtonTextActive,
                ]}
              >
                {item}
              </Text>
            </TouchableOpacity>
          )}
        />
      </View>

      <FlatList
        data={filteredHistory}
        renderItem={renderItem}
        keyExtractor={(item, index) => `${item.timestamp}-${index}`}
        contentContainerStyle={styles.listContent}
        ListEmptyComponent={renderEmptyList}
        refreshControl={
          <RefreshControl
            refreshing={refreshing}
            onRefresh={onRefresh}
            colors={['#4CAF50']}
          />
        }
      />
    </View>
  );
}

